sql:
SELECT COUNT(*)
FROM transactions
WHERE user_id = 1 AND transaction_type = 'buy';

SELECT user_id, COUNT(*) AS number_of_teams
FROM user_teams
GROUP BY user_id;

SELECT COUNT(DISTINCT user_id) 
FROM user_teams 
WHERE team_id = 0;

SELECT AVG(salary_amount) AS average_salary
FROM salaries
WHERE season = '2023';

SELECT user_teams.team_name
FROM user_teams
WHERE user_teams.user_id = 1 AND user_teams.team_value > 50;

SELECT u.user_name
FROM salaries s
JOIN users u ON s.player_id = u.user_id
WHERE s.salary_amount > (
  SELECT AVG(salary_amount) FROM salaries
);

SELECT COUNT(DISTINCT player_id) AS players_count
FROM salaries
WHERE contract_type = 'guaranteed';

SELECT player_id, injury_description, recovery_date
FROM injuries
WHERE recovery_date < date('now');

SELECT pg.player_id, pg.game_id, pg.performance_score, g.game_name
FROM player_game_stats AS pg
JOIN games AS g ON pg.game_id = g.game_id;

